#include <stdio.h>
#include <stdint.h>

static unsigned long long gcd_ull(unsigned long long a, unsigned long long b) {
    while (b) {
        unsigned long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long A,B,C,D,K;
        scanf("%llu %llu %llu %llu %llu", &A, &B, &C, &D, &K);
        unsigned long long g1 = gcd_ull(A, B);
        unsigned long long g2 = gcd_ull(C, D);
        unsigned long long g = gcd_ull(g1, g2);
        __int128 L128 = (__int128)(g1 / g) * (__int128)g2; // lcm
        unsigned long long ans;
        if (L128 > ( __int128)K) {
            ans = 1ULL;
        } else {
            unsigned long long L = (unsigned long long)L128;
            unsigned long long cnt = K / L;
            ans = 2ULL * cnt + 1ULL;
        }
        printf("%llu\n", ans);
    }
    return 0;
}

